/*@ Extern Coq (count_divisors_spec : Z -> Z) */
/*@ Import Coq Require Import count_divisors */

int count_divisors(int n)
/*@ Require
      1 <= n && n < INT_MAX && emp
    Ensure
      __return == count_divisors_spec(n@pre) && emp
*/
{
    int d;
    int cnt = 0;

    for (d = 1; d <= n; ++d) {
        if (n % d == 0) {
            cnt++;
        }
    }

    return cnt;
}
Require Import ZArith.

Open Scope Z_scope.

Fixpoint count_divisors_upto (n : Z) (fuel : nat) : Z :=
  match fuel with
  | O => 0
  | S k =>
      count_divisors_upto n k +
      (if Z.eq_dec (Z.rem n (Z.of_nat (S k))) 0 then 1 else 0)
  end.

Definition count_divisors_spec (n : Z) : Z :=
  count_divisors_upto n (Z.to_nat n).
